package main

import (
	"gno.land/p/sys/validators"
	"gno.land/r/gov/dao"
	valr "gno.land/r/sys/validators/v2"
)

func main() {
	r := valr.NewPropRequest(
		func() []validators.Validator {
			return []validators.Validator{
				{
					Address:     address("g1d5hh9fw3l00gugfzafskaxqlmsyvxfaj6l2q60"),
					VotingPower: 0,
				},
			}
		},
		"Remove validator g1d5hh9fw3l00gugfzafskaxqlmsyvxfaj6l2q60",
		"Remove validator g1d5hh9fw3l00gugfzafskaxqlmsyvxfaj6l2q60 from the validator set",
	)
	pid := dao.MustCreateProposal(cross, r)
	dao.MustVoteOnProposal(cross, dao.VoteRequest{Option: dao.YesVote, ProposalID: pid})
	dao.ExecuteProposal(cross, pid)
}
